import styled from "styled-components";

export const Container = styled.div`
    color: whitesmoke;
    display: flex;
    flex-direction: column;
    border: 1px solid whitesmoke;
    margin: 1vh 1vw;
    padding-top: 5vh;
    text-align: center;
    align-items: center;
    min-height: 75vh;
    color: whitesmoke;

    :hover{
        border: 1px solid #e50914;
        cursor: pointer;
    }

    h4{
        margin: 1vh 0;
        color: whitesmoke;
    }
    img{
        max-height: 45vh;
        
    
    }


`
